    totalAnchors: number;
    avgQualityScore: number;
    privacyTier: PrivacyTier;
    epsilonSpent: number;
    deltaSpent: number;
    compressionRatio: number;
  };
  timestamp: number;
}

/**
 * Aggregated anchor from multiple colonies
 */
export interface AggregatedAnchor {
  anchorId: string;
  layerId: number;
  aggregatedEmbedding: number[];
  aggregatedKeys: Float32Array;
  aggregatedValues: Float32Array;
  sourceColonies: string[];
  qualityScores: number[];
  weights: number[];
  aggregationMetadata: {
    colonyCount: number;
    avgQuality: number;
    minQuality: number;
    maxQuality: number;
    privacyPreserved: boolean;
  };
  createdAt: number;
}

/**
 * Privacy budget tracking for anchor sharing
 */
export interface AnchorPrivacyBudget {
  colonyId: string;
  privacyTier: PrivacyTier;
  epsilonSpent: number;
  deltaSpent: number;
  epsilonLimit: number;
  deltaLimit: number;
  anchorsShared: number;
  anchorsReceived: number;
  lastUpdated: number;
}

